--
-- Table structure for table `customers`
--

CREATE TABLE `customers` (
  `iCustomerId` int(11) NOT NULL,
  `customer_name` varchar(222) NOT NULL,
  `customer_number` varchar(222) NOT NULL,
  `phone` varchar(222) NOT NULL,
  `address` varchar(222) NOT NULL,
  `tehsil` varchar(222) NOT NULL,
  `district` varchar(222) NOT NULL,
  `pincode` varchar(222) NOT NULL,
  `pan_number` varchar(222) NOT NULL,
  `aadhar_number` varchar(222) NOT NULL,
  `our_branch` varchar(222) NOT NULL,
  `manager_name` varchar(222) NOT NULL,
  `sourcing_name` varchar(222) NOT NULL,
  `financier_name` varchar(222) NOT NULL,
  `vehicle_no` varchar(222) NOT NULL,
  `loan_amount_required` varchar(222) NOT NULL,
  `irr_requested` varchar(222) NOT NULL,
  `active` int(11) NOT NULL,
  `create_date` datetime NOT NULL DEFAULT current_timestamp(),
  `user_id` int(11) NOT NULL,
  `updater_id` int(11) NOT NULL,
  `update_date` datetime NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

